start.filterFormula:
AND(
  /* 無限ループ防止：フロー起因更新では起動しない */
  NOT(
    ISCHANGED({!$Record.flowUpdateOccurred__c})
  ),

  OR(
    /* 1. 単価に関連する項目が変更 */
    ISCHANGED({!$Record.ST_unit_price_wao__c}),
    ISCHANGED({!$Record.unitDiscountAmount__c}),

    /* 2. 新規作成: sortOrder または primarySortOrder がブランク AND 品目が存在 */
    AND(
      ISNEW(),
      OR(
        ISBLANK({!$Record.sortOrder__c}),
        ISBLANK({!$Record.primarySortOrder__c})
      ),
      NOT(ISBLANK({!$Record.ST_item__c}))
    ),

    /* 3. 一括処理フラグが変更 */
    ISCHANGED({!$Record.isBulkProcess__c}),

    /* 4. 更新: sortOrder または primarySortOrder が 更新されたAND更新後値あり AND 品目が存在 */
    AND(
      NOT(ISNEW()),
      OR(
        AND(
          ISCHANGED({!$Record.sortOrder__c}),
          NOT(ISBLANK({!$Record.sortOrder__c}))
        ),
        AND(
          ISCHANGED({!$Record.primarySortOrder__c}),
          NOT(ISBLANK({!$Record.primarySortOrder__c}))
        )
      ),
      NOT(ISBLANK({!$Record.ST_item__c}))
    )
  )
)
